import { db } from '../config/firebase';
import { collection, getDocs } from "firebase/firestore";
import Fuse from 'fuse.js';

export async function citysuggester(city_name) {
  const citiesRef = collection(db, 'City');
  const querySnapshot = await getDocs(citiesRef);

  const cityData = [];
  querySnapshot.forEach((doc) => {
    const cityDoc = doc.data();
    cityData.push({ id: doc.id, ...cityDoc });
  });

  const options = {
    includeScore: true,
    keys: ['id']
  };

  const fuse = new Fuse(cityData, options);
  const result = fuse.search(city_name);

  if (result.length === 0) {
    return null;
  }

  // Sort the results by score (closest match first) and filter out duplicates by document ID
  const filteredResults = result
    .sort((a, b) => a.score - b.score)
    .filter((value, index, array) => index === 0 || value.item.id !== array[index - 1].item.id);

  // Return the city name with the highest NB ROUTE VIEWED
  return filteredResults.reduce((prev, current) => prev.nbrSessions > current.item.nbrSessions ? prev : current.item).id;
}
